        <p className="max-w-2xl text-foreground text-lg leading-relaxed">
          {tagline}
        </p>

        <Separator className="bg-border/50" />

        <div className="grid grid-cols-1 gap-16 lg:grid-cols-[minmax(0,1fr)_280px]">
          <div className="min-w-0 space-y-8">
            {featuredImage && (
              <div className="relative aspect-16/9 overflow-hidden">
                <Image
                  alt={title}
                  className="h-full w-full object-cover"
                  fill
                  priority
                  src={featuredImage}
                />
              </div>
            )}
            <div className="max-w-none">
              <MDXContent components={mdxComponents} />
            </div>
          </div>

          <IntegrationSidebar
            category={category}
            docsUrl={docsUrl}
            icon={Icon}
            status={derivedStatus}
            title={title}
          />
        </div>

        {(() => {
          const related = getIntegrationPages().filter(
            (p) => p.slugs[0] !== slug
          );
          if (related.length === 0) {
            return null;
          }
          return (
            <section className="pt-16">
              <h2 className="mb-6 font-medium font-pp text-xl">
                Other integrations
              </h2>
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
                {related.map((p) => {
                  const rSlug = p.slugs[0] ?? "";
                  const RIcon = p.data.providerId
                    ? getProviderIcon(p.data.providerId)
                    : undefined;
                  return (
                    <NavLink
                      className="group flex h-[200px] flex-col justify-between gap-6 overflow-hidden rounded-md bg-accent/40 p-6 transition-colors hover:bg-accent"
                      href={`/integrations/${rSlug}` as Route}
                      key={rSlug}
                      prefetch
                    >
                      {RIcon && (
                        <RIcon aria-hidden className="size-5 text-foreground" />
                      )}
                      <div className="flex flex-col gap-3">
                        <h3 className="font-medium font-pp text-foreground text-xl">
                          {p.data.title}
                        </h3>
                        <p className="line-clamp-2 text-muted-foreground text-sm leading-relaxed">
                          {p.data.tagline}
                        </p>
                      </div>
                    </NavLink>
                  );
                })}
              </div>
            </section>
          );
        })()}

        {(() => {
          const allSorted = [...getIntegrationPages()].sort((a, b) =>
            a.data.title.localeCompare(b.data.title)
          );
          const idx = allSorted.findIndex((p) => p.slugs[0] === slug);
          const prev = idx > 0 ? allSorted[idx - 1] : null;
          const next =
            idx >= 0 && idx < allSorted.length - 1 ? allSorted[idx + 1] : null;
          if (!(prev || next)) {
            return null;
          }
          return (
            <nav
              aria-label="Integration navigation"
              className="grid grid-cols-1 gap-4 pt-16 md:grid-cols-2"
            >
              {prev ? (
                <NavLink
                  className="group flex flex-col gap-1 text-muted-foreground hover:text-foreground"
                  href={`/integrations/${prev.slugs[0]}` as Route}
                  prefetch
                >
                  <span className="flex items-center gap-1 text-sm">
                    <ChevronLeft className="h-4 w-4" />
                    Previous
                  </span>
                  <span className="line-clamp-2 font-medium text-foreground text-sm">
                    {prev.data.title}
                  </span>
                </NavLink>
              ) : (
                <div />
              )}
              {next ? (
                <NavLink
                  className="group flex flex-col gap-1 text-muted-foreground hover:text-foreground md:items-end"
                  href={`/integrations/${next.slugs[0]}` as Route}
                  prefetch
                >
                  <span className="flex items-center gap-1 text-sm">
                    Next
                    <ChevronRight className="h-4 w-4" />
                  </span>
                  <span className="line-clamp-2 font-medium text-foreground text-sm md:text-right">
                    {next.data.title}
                  </span>
                </NavLink>
              ) : (
                <div />
              )}
            </nav>
          );
        })()}
      </article>
    </div>
  );
}

